  methods: {
    getOrigin(message) {
      return message.from == this.recipient.summonerName;
    },
    toggleOpen() {
      if (!this.isOpen) {
        this.$socket.sendSystemMessage("MESSAGE_PRIVATE_GET", {
          data: this.recipient
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
          }
          this.$store.dispatch("setPrivateChatReadMessages", this.recipient);
        });
      }
      this.$store.dispatch("setPrivateChatStatus", {
        summonerName: this.recipient.summonerName,
        change: "toggle"
      });
    },
    closeChat() {
      this.$store.dispatch("setPrivateChatClosed", this.recipient);
    },
    formatTime(message) {
      return `${moment(message.messageTimestamp).format("HH:mm")}`;
    },
    sendMessage() {
      const message = this.$refs.chatInput.value;
      if (message.trim() == "") {
        return;
      }
      this.$refs.chatInput.value = "";
      this.$socket.sendSystemMessage("MESSAGE_PRIVATE", {
        data: this.recipient,
        message: message,
        from: this.user.summonerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    }
  },
  updated() {
    const container = this.$el.querySelector("#messages");
    container.scrollTop = container.scrollHeight;
  },
  mounted() {
    const container = this.$el.querySelector("#messages");
    container.scrollTop = container.scrollHeight;
  },
  computed: mapState({
    user: state => state.user,
    hasUnread(state) {
      const thischat = state.privateChat.chatMessages[this.recipient.summonerName];
      let unreadMessages = 0;
      if (thischat) {
        unreadMessages = thischat.filter(message => {
          return !message.read;
        }).length;
      }
      if (!this.isOpen && unreadMessages > 0) {
        return true;
      } else {
        return false;
      }
    },
    isOpen(state) {
      return state.privateChat.openChats.filter(recipient => {
        return recipient.summonerName == this.recipient.summonerName && recipient.shows;
      }).length > 0;
    },
    messages(state) {
      const msgs = [...state.privateChat.chatMessages[this.recipient.summonerName]];
      if (msgs) {
        msgs.reverse();
      }
